agent-browser --auto-connect eval --stdin 2>&1 <<'JS'
// Pull the first 5 timeline posts into a structured array
const articles = Array.from(document.querySelectorAll('article[data-testid="tweet"]')).slice(0, 5);
const out = articles.map(a => {
  const handle = a.querySelector('[data-testid="User-Name"] a[href^="/"]')?.getAttribute('href') || null;
  const text = a.querySelector('[data-testid="tweetText"]')?.innerText || '';
  const timeEl = a.querySelector('time');
  const postHref = timeEl?.closest('a')?.getAttribute('href') || null;
  const posted = timeEl?.getAttribute('datetime') || null;
  const likes = a.querySelector('[data-testid="like"]')?.innerText || '';
  const replies = a.querySelector('[data-testid="reply"]')?.innerText || '';
  const reposts = a.querySelector('[data-testid="retweet"]')?.innerText || '';
  return { author_handle: handle, post_url: postHref, posted, text: text.slice(0, 140), likes, replies, reposts };
});
JSON.stringify(out, null, 2);
JS

